cdef Matrix33 rotate_x(double ang):
    cdef double c = cos(ang)
    cdef double s = sin(ang)
    cdef vec3 c1 = vec3(1,0,0)
    cdef vec3 c2 = vec3(0,c,-s)
    cdef vec3 c3 = vec3(0,s,c)
